#include<bits/stdc++.h>
using namespace std;

#define ll long long
struct node
{
    int v,w;
}a[1005];

ll n,t,p,dp[10001];
int cmp(node a,node b)
{
    return a.w<b.w;
 } 
int main(){
	cin>>n>>p>>t;
	for(int i=1;i<=n;i++){
		cin>>a[i].w>>a[i].v;
	}
    sort(a+1,a+n+1,cmp);
    for(int i=1;i<=n;i++)
        for(int j=t;j>=a[i].w;j--)
        {
            dp[j]=max(dp[j],dp[j-a[i].w]+a[i].v);
            if(dp[t]>=p)

            {
                cout<<a[i].w;
                return 0;
            }
        }

            cout<<"No Solution!";


	return 0;
}
